import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink", () => {
  it("should process all items from an async source", (done) => {
    const collected: number[] = [];
    const values = [1, 2, 3];
    let index = 0;

    function asyncSource(end: any, cb: (end: any, data?: any) => void) {
      if (end) return cb(end, null);
      const i = index++;
      setImmediate(() => {
        if (i >= values.length) cb(true, null);
        else cb(null, values[i]);
      });
    }

    const sink = drain(
      (data: number) => { collected.push(data); },
      (err: any) => {
        expect(err).toBeNull();
        expect(collected).toEqual([1, 2, 3]);
        done();
      }
    );

    sink(asyncSource);
  });
});
```
